import{_ as a,o as t,c as r,a2 as n}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"ADR-002 — Vanilla JS, no framework","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-002.md","filePath":"adr/ADR-002.md"}'),o={name:"adr/ADR-002.md"};function i(s,e,l,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-002-—-vanilla-js-no-framework" tabindex="-1">ADR-002 — Vanilla JS, no framework <a class="header-anchor" href="#adr-002-—-vanilla-js-no-framework" aria-label="Permalink to &quot;ADR-002 — Vanilla JS, no framework&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-01 TA anchor · §stack · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The project needs a consistent approach to UI and component structure. The primary rendering targets are Three.js and Canvas 2D — both imperative APIs. A declarative component framework would add abstraction on top of imperative rendering without clear benefit.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Vanilla JavaScript throughout. No React, Vue, Svelte, or any component framework.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The rendering surfaces are inherently imperative — Three.js scenes, Canvas 2D draw calls. Wrapping them in a reactive component system adds complexity without benefit. The six screens are distinct enough that shared component logic is limited to the nav bar and detail panel — both manageable as vanilla JS modules.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>React — good for data-driven UI; poor fit for canvas/WebGL-heavy screens. Adds significant bundle size.</li><li>Svelte — smaller than React; still adds compilation step and abstraction layer not needed here.</li><li>Lit — lightweight web components; reasonable alternative but adds a dependency without clear gain.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: zero framework overhead; all code directly readable; no framework upgrade risk. Negative: shared component patterns require discipline without framework enforcement.</p>',12)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
